+    /// Compute a content hash for verification.
+    fn content_hash(data: &[Vec<u8>]) -> u64 {
+        let mut hasher = DefaultHasher::new();
+        for chunk in data {
+            chunk.hash(&mut hasher);
+        }
+        hasher.finish()
+    }
